INSERT INTO achievers (name_ja,name_en,name_kana,birth_year,death_year,birth_place,primary_era_id,domain,sub_domain,achievement_summary,notable_works,family_class,education_path,fame_source,fame_score,is_traditional_great,is_local_excellent,data_completeness,source_team,source_url,notes)
SELECT name_ja,name_en,name_kana,birth_year,death_year,birth_place,'showa_post','sports',sub_domain,achievement_summary,notable_works,'other',education_path,'wikipedia_ja',fame_score,is_traditional_great,is_local_excellent,72,'codex_showa_post_sports',source_url,notes
FROM vals
WHERE NOT EXISTS (SELECT 1 FROM achievers a WHERE a.name_ja=vals.name_ja AND a.birth_year=vals.birth_year);

COMMIT;

SELECT 'after_batch_2', COUNT(*) FROM achievers WHERE source_team='codex_showa_post_sports';

BEGIN TRANSACTION;

WITH caps(name_ja,birth_year,capability_id,score,evidence_quote,notes) AS (
SELECT name_ja,birth_year,'age_resilience',9,'昭和後期のスポーツで競技成績または指導実績を残し、長期の鍛錬と勝負への適応を示した。','競技継続力' FROM achievers WHERE source_team='codex_showa_post_sports'
UNION ALL
SELECT name_ja,birth_year,'age_meta_learning',8,'技術・戦術・身体管理を学習し続け、選手または指導者として競技水準の向上に貢献した。','学習と技能改善' FROM achievers WHERE source_team='codex_showa_post_sports'
UNION ALL
SELECT name_ja,birth_year,'val_collective',7,'チーム、部屋、実業団、学校、代表組織などの中で役割を果たし、競技文化の形成に関わった。','組織内協働'
FROM achievers WHERE source_team='codex_showa_post_sports' AND sub_domain IN ('プロ野球','大相撲','バレーボール','サッカー','高校野球指導','プロレス指導','柔道・プロレス')
UNION ALL
SELECT name_ja,birth_year,'cog_creativity',7,'専門技術や戦術、演技・フォームの工夫を通じて、競技の表現や方法に独自性を示した。','技術創造'
FROM achievers WHERE source_team='codex_showa_post_sports' AND sub_domain NOT IN ('プロ野球','大相撲','バレーボール','サッカー','高校野球指導','プロレス指導','柔道・プロレス')
)
INSERT INTO achiever_capabilities (achiever_id,capability_id,score,evidence_quote,evidence_source,notes)
SELECT a.id,c.capability_id,c.score,c.evidence_quote,a.source_url,c.notes
FROM caps c
JOIN achievers a ON a.name_ja=c.name_ja AND a.birth_year=c.birth_year
WHERE NOT EXISTS (
  SELECT 1 FROM achiever_capabilities ac
  WHERE ac.achiever_id=a.id AND ac.capability_id=c.capability_id
);

COMMIT;

SELECT 'capabilities_added', COUNT(*)
FROM achiever_capabilities ac
JOIN achievers a ON a.id=ac.achiever_id
WHERE a.source_team='codex_showa_post_sports';

